Human: </additional_settings>","user_suffix":"<additional_settings>","char_prefix":"

Assistant: </additional_settings>","char_suffix":"<additional_settings>","prefix_system":"","suffix_system":"","enable_squashed_separator":true,"squashed_separator_regex":false,"squashed_separator_string":"<|no-trans|>","squashed_post_script_enable":true,"squashed_post_script":"content => {
  // 分区整理脚本
  // 作用：
  // 1. 依据两个锚点，把 depth 注入内容拆成三段
  // 2. 填回 world_summary / additional_info / additional_constraints
  // 3. 把 Human / Assistant 改成 Participant / Recorder
  // 4. 给最后一条 Participant 输入补上 Participant_input 标签
  // 5. 清理正则脚本产生的 <|placeholder|> 占位内容

  const markWorld = '<|ws_slot|>';
  const markInfo = '<|ai_slot|>';
  const markRule = '<|ac_slot|>';

  const cutHigh = '<@Cut_900>';
  const cutLow = '<@Cut_2>';

  const hasWorld = content.includes(markWorld);
  const hasInfo = content.includes(markInfo);
  const hasRule = content.includes(markRule);

  const highPos = content.indexOf(cutHigh);
  const lowPos = content.indexOf(cutLow);

  const worldParts = [];
  const infoParts = [];
  const ruleParts = [];

  const keepHeads = ['\n\n[Start]', '\n\nHuman:', '\n\nAssistant:', '\n\nParticipant:', '\n\nRecorder:'];

  let result = content.replace(/<additional_settings>([\s\S]*?)<\/additional_settings>/g, (whole, inner, offset) => {
    let area = null;

    if (lowPos !== -1 && offset > lowPos) area = 'rule';
    else if (highPos !== -1 && offset < highPos) area = 'world';
    else if (highPos !== -1 && lowPos !== -1 && offset > highPos) area = 'info';
    else if (highPos !== -1 && lowPos === -1 && offset > highPos) area = 'info';

    if (!area) return inner;
    if (area === 'world' && !hasWorld) return inner;
    if (area === 'info' && !hasInfo) return inner;
    if (area === 'rule' && !hasRule) return inner;

    let body = inner;
    let keep = '';

    keepHeads.forEach(head => {
      if (body.includes(head)) {
        body = body.replace(head, '');
        keep += head;
      }
    });

    if (body.trim()) {
      if (area === 'world') worldParts.push(body);
      else if (area === 'info') infoParts.push(body);
      else ruleParts.push(body);
    }

    return keep;
  });

  result = result.replace(cutHigh, '').replace(cutLow, '');

  const inject = (text, slot, value) => text.split(slot).join(value);
  result = inject(result, markWorld, worldParts.join('\n\n').trim());
  result = inject(result, markInfo, infoParts.join('\n\n').trim());
  result = inject(result, markRule, ruleParts.join('\n\n').trim());

  result = result
    .replace(/<additional_settings>\s*<\/additional_settings>/g, '')
    .replace(/<\/additional_settings>/g, '')
    .replace(/<additional_settings>/g, '')
    .replace(/<\|additional_info\|>/g, '')
    .replace(/<\|world_summary\|>/g, '')
    .replace(/<\|additional_constraints\|>/g, '');

  result = result
    .replace(/^Human:/gm, 'Participant:')
    .replace(/^Assistant:/gm, 'Recorder:');

  // 清理正则脚本产生的 <|placeholder|> 占位内容
  // 正则脚本"仅保留最新用户输入"将历史用户消息替换为 <|placeholder|>，
  // 而非空字符串，以防止 ChatSquash 跳过这些消息导致角色合并。
  // 这里移除内容仅为 <|placeholder|> 的 Participant: 行
  result = result.replace(/\n\nParticipant:<\|placeholder\|>/g, '');

  // 清理所有 <|placeholder|> 残留（防止遗漏）
  result = result.replace(/<\|placeholder\|>/g, '');

  const lastP = result.lastIndexOf('\n\nParticipant:');
  if (lastP !== -1) {
    result = result.substring(0, lastP) + result.substring(lastP).replace(
      /\n\nParticipant:([\s\S]+?)(\n+Recorder:)/,
      '\n\nParticipant:<Participant_input>\n$1\n</Participant_input>\n\n$2'
    );
  }

  return result.replace(/\n{3,}/g, '\n\n').trim();
}
